// N3 (3b) — Validación multi-porción + armado de líneas REALES.
// Genera el source_event ÚNICO del evento y deja cada línea lista para N4.5/N5.
// NO registra nada acá. El registro ocurre en N5 (transaccional).

function esc(v){ if(v===null||v===undefined) return '';
  return String(v).replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;')
    .replace(/"/g,'&quot;').replace(/'/g,'&#39;'); }
const fmt = n => Number(n).toLocaleString('es-AR');

const form = $('N1 Form Trigger (porciones)').item.json;
const row = items[0].json;  // N2 SIEMPRE 1 fila

function errNeg(m){ return [{ json:{ _error_negocio:true, mensaje:m, mensaje_html:esc(m) } }]; }

// 1) ID inexistente
if (!row.reserva_encontrada) {
  return errNeg('No encontré una reserva con ese ID. Revisá el listado.');
}
const saldo_real = Number(row.saldo_real);

// 2) Normalizar montos (vacío -> 0)
const ef = Number(form.monto_efectivo || 0);
const tr = Number(form.monto_transferencia || 0);
const ot = Number(form.monto_otros || 0);

// 3) Cada monto numérico y >= 0
for (const [nombre, val] of [['efectivo',ef],['transferencia',tr],['otros',ot]]) {
  if (!Number.isFinite(val) || val < 0) {
    return errNeg('El monto de la porción ' + nombre + ' debe ser un número mayor o igual a cero.');
  }
}

// 4) Suma de porciones de saldo
const suma_saldo = ef + tr + ot;
if (suma_saldo <= 0) {
  return errNeg('Tenés que cargar al menos una porción de saldo mayor a cero.');
}
if (suma_saldo > saldo_real) {
  return errNeg('La suma de las porciones ($' + fmt(suma_saldo) + ') supera el saldo pendiente ($' + fmt(saldo_real) + ').');
}

// 5) Subtipo de transferencia: opcional, default bancaria; MP solo si se elige.
const MEDIO_TRANSFERENCIA = (form.subtipo_transferencia === 'MP')
  ? 'transferencia_mp'
  : 'transferencia_bancaria';

// 6) Otros: si monto>0 exige origen Y descripción (3b, alineado a 9B §7.1/§10.1)
const origen = form.origen_otros;
const origen_valido = (origen === 'USD' || origen === 'cripto' || origen === 'otro');
const desc = (form.desc_otros || '').trim();
if (ot > 0) {
  if (!origen_valido) {
    return errNeg('Cargaste una porción "otros" pero no elegiste el origen (USD, cripto u otro).');
  }
  if (desc === '') {
    return errNeg('La porción "otros" exige una descripción (por ejemplo: USDT, pago en especie).');
  }
}
if (ot === 0 && origen_valido) {
  return errNeg('Elegiste un origen para "otros" pero el monto de otros es 0.');
}

// 7) Recargo 5% sobre la porción de transferencia (interno, no lo carga el operador)
const recargo = tr > 0 ? Math.round(tr * 0.05) : 0;
const total_paga = suma_saldo + recargo;
const saldo_proyectado = saldo_real - suma_saldo;

// 8) source_event ÚNICO del evento (mismo para TODAS las líneas — R4).
//    Preferir execution.id si n8n lo expone en Code; si no, ms + random corto.
//    Evita colisión si el mismo operador registra dos cobranzas en el mismo segundo.
const validado_por = form.validado_por;
const op = String(validado_por || 'desconocido').toLowerCase();
let uniq;
try {
  const exId = (typeof $execution !== 'undefined' && $execution && $execution.id) ? String($execution.id) : null;
  uniq = exId ? ('ex' + exId) : (Date.now().toString(36) + '_' + Math.random().toString(36).slice(2, 8));
} catch (e) {
  uniq = Date.now().toString(36) + '_' + Math.random().toString(36).slice(2, 8);
}
const source_event = 'n8n_test_w09_cobranza_' + op + '_' + uniq;

// Nota de "otros" con trazabilidad clara (medio_original + registrado_como)
const nota_otros = ot > 0
  ? ('medio_original=otros; origen_otros=' + origen + '; descripcion_otros=' + desc + '; registrado_como=efectivo_ars')
  : '';

// 9) Armar la LISTA de líneas payload-ready.
//    Orden confirmado: efectivo -> otros -> transferencia(saldo) -> transferencia(extra).
//    El `extra` queda inmediatamente después de su `saldo` de transferencia.
const lineas = [];

function baseLinea(tipo, medio_pago, monto, notas_linea) {
  return {
    tipo,
    medio_pago,
    monto_esperado: monto,
    monto_recibido: monto,        // capa fuerza recibido = esperado
    estado_inicial: 'confirmado', // capa fuerza confirmado
    moneda: 'ARS',
    id_reserva: row.id_reserva,
    validado_por,
    source_event,
    notas: notas_linea
  };
}

if (ef > 0) {
  lineas.push(baseLinea('saldo', 'efectivo', ef, 'porcion_efectivo'));
}
if (ot > 0) {
  lineas.push(baseLinea('saldo', 'efectivo', ot, nota_otros));
}
if (tr > 0) {
  lineas.push(baseLinea('saldo', MEDIO_TRANSFERENCIA, tr, 'porcion_transferencia'));
  lineas.push(baseLinea('extra', MEDIO_TRANSFERENCIA, recargo, 'recargo_5_saldo_transferencia'));
}

// 10) Filas HTML del resumen (escapadas) para N4
let lineas_html = '';
if (ef > 0) lineas_html += '<tr><td>Efectivo</td><td>$' + esc(fmt(ef)) + '</td></tr>';
if (tr > 0) {
  const etq = (MEDIO_TRANSFERENCIA === 'transferencia_mp') ? 'Transferencia (MP)' : 'Transferencia (bancaria)';
  lineas_html += '<tr><td>' + etq + '</td><td>$' + esc(fmt(tr)) + '</td></tr>';
}
if (ot > 0) lineas_html += '<tr><td>Otros (' + esc(origen) + ': ' + esc(desc) + ')</td><td>$' + esc(fmt(ot)) + '</td></tr>';

// Conteos esperados para la verificación posterior (N6)
const cant_saldo = (ef > 0 ? 1 : 0) + (ot > 0 ? 1 : 0) + (tr > 0 ? 1 : 0);
const cant_extra = (tr > 0 ? 1 : 0);

return [{ json: {
  _error_negocio: false,
  id_reserva: row.id_reserva, cabana: row.cabana,
  fecha_checkin: row.fecha_checkin, fecha_checkout: row.fecha_checkout,
  saldo_real, suma_saldo, recargo, total_paga, saldo_proyectado,
  lineas, validado_por, notas: form.notas || '',
  source_event,
  medio_transferencia: MEDIO_TRANSFERENCIA,
  // esperados para N6
  cant_lineas: lineas.length,
  cant_saldo, cant_extra,
  suma_saldo_esperada: suma_saldo,
  suma_extra_esperada: recargo,
  // campos escapados para N4
  cabana_html: esc(row.cabana),
  fecha_checkin_html: esc(row.fecha_checkin),
  fecha_checkout_html: esc(row.fecha_checkout),
  id_reserva_html: esc(row.id_reserva),
  saldo_real_html: esc(fmt(saldo_real)),
  suma_saldo_html: esc(fmt(suma_saldo)),
  recargo_html: esc(fmt(recargo)),
  total_paga_html: esc(fmt(total_paga)),
  saldo_proyectado_html: esc(fmt(saldo_proyectado)),
  lineas_html
} }];

// N4.5 (3b) — Expandir lineas[] a N ítems, uno por línea de pago.
// Recién acá (post-confirmación de N4) se pasa de 1 evento a N payloads.
// Cada ítem lleva el payload JSONB completo para registrar_pago + metadatos.

const ev = $('N3 Validación multi-porción').item.json;
const lineas = ev.lineas || [];

if (!Array.isArray(lineas) || lineas.length === 0) {
  // Defensa: no debería ocurrir (N3 ya valida suma_saldo>0).
  throw new Error('N4.5: no hay líneas para registrar.');
}

return lineas.map((l, idx) => {
  const payload = {
    id_reserva:     l.id_reserva,
    tipo:           l.tipo,
    medio_pago:     l.medio_pago,
    monto_esperado: l.monto_esperado,
    monto_recibido: l.monto_recibido,   // = esperado (forzado en N3)
    moneda:         l.moneda || 'ARS',
    estado_inicial: l.estado_inicial,   // 'confirmado'
    validado_por:   l.validado_por,
    notas:          l.notas,
    source_event:   l.source_event      // ÚNICO del evento, sin mutar (R4)
  };
  return { json: {
    payload,
    _idx: idx,
    _tipo: l.tipo,
    _medio: l.medio_pago,
    _monto: l.monto_esperado,
    source_event: l.source_event,
    id_reserva: l.id_reserva
  } };
});

// N6b (3b) — Control de la verificación posterior.
// Lee la fila de N6 desenvolviendo la columna (item.resultado / alias),
// y la compara contra los esperados calculados en N3.

const raw = items[0].json;
// El nodo Postgres devuelve la fila directamente; por robustez, desenvolver
// si viniera anidada bajo una columna (consistente con L-8D-01).
const v = (raw && raw.resultado !== undefined) ? raw.resultado : raw;

const ev = $('N3 Validación multi-porción').item.json;

const fmt = n => Number(n).toLocaleString('es-AR');

const cant_pagos          = Number(v.cant_pagos || 0);
const cant_confirmados    = Number(v.cant_confirmados || 0);
const cant_no_confirmados = Number(v.cant_no_confirmados || 0);
const suma_saldo          = Number(v.suma_saldo || 0);
const suma_extra          = Number(v.suma_extra || 0);
const cant_extra_total    = Number(v.cant_extra_total || 0);
const cant_extra_marca_ok = Number(v.cant_extra_marcado_ok || 0);
const saldo_real_post     = Number(v.saldo_real_post);  // recalculado en N6 desde la base

const problemas = [];

// 1) cantidad de pagos = esperada
if (cant_pagos !== Number(ev.cant_lineas)) {
  problemas.push('cantidad de pagos registrada (' + cant_pagos + ') ≠ esperada (' + ev.cant_lineas + ')');
}
// 2) todos confirmados
if (cant_no_confirmados > 0 || cant_confirmados !== cant_pagos) {
  problemas.push('hay pagos no confirmados (' + cant_no_confirmados + ')');
}
// 3) SUM(saldo) = suma de porciones que reducen saldo
if (suma_saldo !== Number(ev.suma_saldo_esperada)) {
  problemas.push('suma saldo registrada ($' + fmt(suma_saldo) + ') ≠ esperada ($' + fmt(ev.suma_saldo_esperada) + ')');
}
// 4) SUM(extra) = 5% calculado
if (suma_extra !== Number(ev.suma_extra_esperada)) {
  problemas.push('suma extra registrada ($' + fmt(suma_extra) + ') ≠ recargo esperado ($' + fmt(ev.suma_extra_esperada) + ')');
}
// 5) extra marcado correctamente (si hubo extra)
if (cant_extra_total !== cant_extra_marca_ok) {
  problemas.push('el recargo no quedó marcado recargo_5_saldo_transferencia en source_event y notas');
}

const saldo_anterior = Number(ev.saldo_real);
const saldo_proyectado = saldo_anterior - suma_saldo;  // proyección (baja solo por saldo)

// 6) El saldo REAL recalculado desde la base debe coincidir con la proyección.
//    Si coincide, queda probado que el `extra` NO redujo el saldo de alojamiento.
if (!Number.isFinite(saldo_real_post)) {
  problemas.push('no se pudo recalcular el saldo real post-write de la reserva');
} else if (saldo_real_post !== saldo_proyectado) {
  problemas.push('saldo real recalculado ($' + fmt(saldo_real_post) +
                 ') ≠ proyección saldo_anterior - suma_saldo ($' + fmt(saldo_proyectado) +
                 '). Posible contaminación del saldo por el extra u otro pago.');
}

if (problemas.length > 0) {
  // No revertimos acá (la transacción de N5 ya cerró). Señalamos verificación fallida.
  return [{ json: {
    _verif_ok: false,
    _problemas: problemas,
    _problemas_html: problemas.map(p =>
      String(p).replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;')
    ).join('<br>'),
    source_event: ev.source_event
  } }];
}

return [{ json: {
  _verif_ok: true,
  id_reserva: ev.id_reserva,
  id_reserva_html: ev.id_reserva_html,
  cabana_html: ev.cabana_html,
  cant_lineas: ev.cant_lineas,
  suma_saldo, suma_extra,
  suma_saldo_html: fmt(suma_saldo),
  suma_extra_html: fmt(suma_extra),
  saldo_anterior, saldo_nuevo: saldo_real_post,
  saldo_anterior_html: fmt(saldo_anterior),
  saldo_nuevo_html: fmt(saldo_real_post),
  saldada: (saldo_real_post === 0),
  source_event: ev.source_event
} }];
